"use client";

import { useEffect, useMemo, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import Link from "next/link";

const CUSTOMERS_STORAGE_KEY = "adminCustomers";

type Customer = {
  id: string;
  name: string;
  email: string;
  phone: string;
  address?: string;
  joinDate?: string;
  totalBookings?: number;
  totalSpent?: string;
  status?: string;
  lastBooking?: string;
};

export default function CustomerProfilePage() {
  const params = useParams<{ id: string }>();
  const router = useRouter();
  const [customer, setCustomer] = useState<Customer | null>(null);
  const [ratingForm, setRatingForm] = useState({ provider: "", score: 5, comment: "" });
  const id = params?.id;

  useEffect(() => {
    if (!id) return;
    if (typeof window === "undefined") return;
    try {
      const stored = localStorage.getItem(CUSTOMERS_STORAGE_KEY);
      if (stored) {
        const list: Customer[] = JSON.parse(stored);
        const found = list.find((c) => String(c.id) === String(id));
        if (found) setCustomer(found);
      }
    } catch {}
  }, [id]);

  const initials = useMemo(() => {
    if (!customer?.name) return "?";
    const parts = customer.name.split(" ");
    return parts.slice(0, 2).map((p) => p[0]?.toUpperCase()).join("");
  }, [customer]);

  const submitRating = (e: React.FormEvent) => {
    e.preventDefault();
    // Placeholder: persist ratings as needed
    alert(`Rating saved for ${ratingForm.provider || "provider"}: ${ratingForm.score}/5`);
    setRatingForm({ provider: "", score: 5, comment: "" });
  };

  if (!customer) {
    return (
      <div className="space-y-4">
        <div className="text-sm text-muted-foreground">Loading customer...</div>
        <Button variant="outline" onClick={() => router.push("/admin/customers")}>Back to Customers</Button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-semibold">{customer.name}</h2>
          <p className="text-sm text-muted-foreground">Customer Profile</p>
        </div>
        <Link href="/admin/customers" className="text-sm text-cyan-700 hover:underline">Back to Customers</Link>
      </div>

      <Card>
        <CardContent className="pt-6 space-y-4">
          <div className="flex items-start gap-4">
            <div className="h-12 w-12 rounded-full bg-cyan-100 text-cyan-700 flex items-center justify-center font-semibold">
              {initials}
            </div>
            <div className="space-y-1">
              <div className="text-sm">
                <span className="font-medium">Email:</span>{" "}
                <a href={`mailto:${customer.email}`} className="text-cyan-700 hover:underline">
                  {customer.email}
                </a>
              </div>
              <div className="text-sm"><span className="font-medium">Phone:</span> {customer.phone}</div>
              {customer.address && <div className="text-sm"><span className="font-medium">Address:</span> {customer.address}</div>}
              <div className="text-sm"><span className="font-medium">Status:</span> <Badge variant="secondary">{customer.status || "active"}</Badge></div>
            </div>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 w-full">
            <Button variant="outline" className="bg-slate-100 dark:bg-slate-800/50">
              Deactivate
            </Button>
            <Button variant="outline" className="bg-amber-100 text-amber-800 dark:bg-amber-900/20 dark:text-amber-300">
              Block Access
            </Button>
            <Button className="bg-red-500 hover:bg-red-600 text-white">
              Block From Booking
            </Button>
            <Button variant="outline">Unsubscribe</Button>
          </div>
        </CardContent>
      </Card>

      <div className="flex justify-end">
        <Link href={`/admin/add-booking?customerId=${encodeURIComponent(String(customer.id))}`}>
          <Button
            className="text-white"
            style={{ background: "linear-gradient(135deg, #00BCD4 0%, #00D4E8 100%)" }}
          >
            New Booking
          </Button>
        </Link>
      </div>

      <Tabs defaultValue="profile" className="w-full">
        <TabsList>
          <TabsTrigger value="profile">Profile</TabsTrigger>
          <TabsTrigger value="ratings">Ratings</TabsTrigger>
        </TabsList>

        <TabsContent value="profile">
          <Card>
            <CardHeader>
              <CardTitle>Profile</CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <Label>Name</Label>
                  <Input value={customer.name} disabled />
                </div>
                <div>
                  <Label>Email</Label>
                  <Input value={customer.email} disabled />
                </div>
                <div>
                  <Label>Phone</Label>
                  <Input value={customer.phone} disabled />
                </div>
                <div>
                  <Label>Address</Label>
                  <Input value={customer.address || ""} disabled />
                </div>
                <div>
                  <Label>Member Since</Label>
                  <Input value={customer.joinDate || "-"} disabled />
                </div>
                <div>
                  <Label>Total Spent</Label>
                  <Input value={customer.totalSpent || "$0"} disabled />
                </div>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="ratings">
          <Card>
            <CardHeader>
              <CardTitle>Rate Provider</CardTitle>
            </CardHeader>
            <CardContent>
              <form onSubmit={submitRating} className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="provider">Provider</Label>
                    <Input id="provider" value={ratingForm.provider} onChange={(e) => setRatingForm({ ...ratingForm, provider: e.target.value })} placeholder="e.g. Jane Smith" required />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="score">Rating (1-5)</Label>
                    <Input id="score" type="number" min={1} max={5} value={ratingForm.score} onChange={(e) => setRatingForm({ ...ratingForm, score: Math.max(1, Math.min(5, Number(e.target.value))) })} required />
                  </div>
                </div>
                <div className="space-y-2">
                  <Label htmlFor="comment">Comments</Label>
                  <Textarea id="comment" value={ratingForm.comment} onChange={(e) => setRatingForm({ ...ratingForm, comment: e.target.value })} placeholder="Share feedback about the provider" />
                </div>
                <div className="flex gap-3">
                  <Button type="submit">Submit Rating</Button>
                  <Button type="button" variant="outline" onClick={() => setRatingForm({ provider: "", score: 5, comment: "" })}>Reset</Button>
                </div>
              </form>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}
